import { useState } from 'react';
import { Link, useNavigate } from 'react-router-dom';
import { useForm } from 'react-hook-form';
import { zodResolver } from '@hookform/resolvers/zod';
import { useMutation, useQueryClient } from '@tanstack/react-query';
import { z } from 'zod';
import { toast } from 'sonner';
import { beaconApi } from '@/api/client';
import type { CreateProjectCommand, CreateProjectResult } from '@/api/generated/beacon-api';
import { Icon } from '@/components/Icon';
import { PageHeader } from '@/components/layout/PageHeader';
import { ApiError } from '@/lib/api';
import { useDataSourcesQuery } from '@/routes/data-sources/queries';

const SCHEMA = z.object({
  name: z.string().trim().min(1, 'Name is required').max(200),
  description: z.string().trim().max(2000),
  repositoryUrls: z.string(),
  accessToken: z.string(),
});

type FormValues = z.infer<typeof SCHEMA>;

const DEFAULTS: FormValues = {
  name: '',
  description: '',
  repositoryUrls: '',
  accessToken: '',
};

function splitLines(s: string): string[] {
  return s.split(/\r?\n/).map(x => x.trim()).filter(x => x.length > 0);
}

function useCreateProject() {
  const qc = useQueryClient();
  return useMutation<CreateProjectResult, unknown, CreateProjectCommand>({
    mutationFn: values => beaconApi().createProject(values),
    onSuccess: () => qc.invalidateQueries({ queryKey: ['projects'] }),
  });
}

export default function NewProjectPage() {
  const navigate = useNavigate();
  const dataSources = useDataSourcesQuery();
  const createMutation = useCreateProject();
  const [selectedIds, setSelectedIds] = useState<number[]>([]);

  const {
    register,
    handleSubmit,
    formState: { errors, isSubmitting },
  } = useForm<FormValues>({
    resolver: zodResolver(SCHEMA),
    defaultValues: DEFAULTS,
    mode: 'onTouched',
  });

  const toggleSource = (id: number) =>
    setSelectedIds(prev => prev.includes(id) ? prev.filter(x => x !== id) : [...prev, id]);

  const onSubmit = handleSubmit(async v => {
    try {
      const result = await createMutation.mutateAsync({
        name: v.name.trim(),
        description: v.description.trim() || null,
        dataSourceIds: selectedIds,
        repositoryUrls: splitLines(v.repositoryUrls),
        accessToken: v.accessToken.trim() || null,
      });
      toast.success('Project created');
      navigate(`/projects/${result.projectId}`);
    } catch (err) {
      const message = err instanceof ApiError
        ? err.body || `Create failed (${err.status})`
        : err instanceof Error ? err.message : 'Unknown error';
      toast.error(message);
    }
  });

  const sources = dataSources.data?.entries ?? [];

  return (
    <div className="page">
      <PageHeader
        title="New project"
        sub={
          <span className="muted">
            <Link to="/projects" className="muted">Projects</Link>
            <span style={{ margin: '0 6px' }}>/</span>
            New
          </span>
        }
        actions={
          <Link className="btn" to="/projects">
            Cancel
          </Link>
        }
      />

      <form onSubmit={onSubmit} noValidate>
        <div className="card" style={{ marginBottom: 16 }}>
          <div className="card__body">
            <h3 className="card__title" style={{ margin: '0 0 12px' }}>
              <Icon.Folder size={14} /> Basics
            </h3>

            <div className="q-field">
              <label className="q-label" htmlFor="np-name">
                Project name<span className="q-label__req">*</span>
              </label>
              <input
                id="np-name"
                type="text"
                className={`q-input${errors.name ? ' q-input--error' : ''}`}
                placeholder="Customer analytics"
                {...register('name')}
              />
              {errors.name && <div className="q-error">{errors.name.message}</div>}
            </div>

            <div className="q-field" style={{ marginTop: 14 }}>
              <label className="q-label" htmlFor="np-desc">Description</label>
              <textarea
                id="np-desc"
                rows={3}
                className={`q-input${errors.description ? ' q-input--error' : ''}`}
                placeholder="What this project covers, who owns it, and how it's used."
                {...register('description')}
              />
              {errors.description && <div className="q-error">{errors.description.message}</div>}
            </div>
          </div>
        </div>

        <div className="card" style={{ marginBottom: 16 }}>
          <div className="card__body">
            <h3 className="card__title" style={{ margin: '0 0 4px' }}>
              <Icon.Database size={14} /> Data sources
            </h3>
            <div className="muted" style={{ fontSize: 12, marginBottom: 12 }}>
              Pick the data sources this project should be scoped to. You can change this later.
            </div>

            {dataSources.isLoading && <div className="muted">Loading data sources…</div>}

            {!dataSources.isLoading && sources.length === 0 && (
              <div className="muted" style={{ fontSize: 13 }}>
                No data sources configured yet. <Link to="/data-sources">Add one</Link> first.
              </div>
            )}

            {sources.length > 0 && (
              <div style={{ display: 'grid', gap: 8 }}>
                {sources.map(ds => {
                  const checked = selectedIds.includes(ds.id);
                  return (
                    <label
                      key={ds.id}
                      className="card"
                      style={{
                        padding: '10px 12px',
                        display: 'flex',
                        alignItems: 'center',
                        gap: 12,
                        cursor: 'pointer',
                        background: checked ? 'var(--surface-2)' : undefined,
                      }}
                    >
                      <input
                        type="checkbox"
                        checked={checked}
                        onChange={() => toggleSource(ds.id)}
                      />
                      <div style={{ flex: 1 }}>
                        <div style={{ fontWeight: 600 }}>{ds.name}</div>
                        <div className="muted mono" style={{ fontSize: 12 }}>
                          {ds.dataSourceType}
                          {ds.databaseEngineType && ` · ${ds.databaseEngineType}`}
                        </div>
                      </div>
                    </label>
                  );
                })}
              </div>
            )}
          </div>
        </div>

        <div className="card" style={{ marginBottom: 16 }}>
          <div className="card__body">
            <h3 className="card__title" style={{ margin: '0 0 4px' }}>
              <Icon.Branch size={14} /> Repositories (optional)
            </h3>
            <div className="muted" style={{ fontSize: 12, marginBottom: 12 }}>
              One Git URL per line. Beacon scans linked repos to surface code references.
            </div>

            <div className="q-field">
              <label className="q-label" htmlFor="np-repos">Repository URLs</label>
              <textarea
                id="np-repos"
                rows={3}
                className="q-input mono"
                placeholder="https://github.com/example/repo-a&#10;https://github.com/example/repo-b"
                {...register('repositoryUrls')}
              />
            </div>

            <div className="q-field" style={{ marginTop: 14 }}>
              <label className="q-label" htmlFor="np-token">Personal access token</label>
              <input
                id="np-token"
                type="password"
                className="q-input mono"
                placeholder="Required only for private repositories"
                {...register('accessToken')}
              />
              <div className="q-help">
                Token is encrypted at rest. Required only for private repos; leave empty for public ones.
              </div>
            </div>
          </div>
        </div>

        <div style={{ display: 'flex', justifyContent: 'flex-end', gap: 10 }}>
          <Link className="btn" to="/projects">Cancel</Link>
          <button
            type="submit"
            className="btn btn--primary"
            disabled={isSubmitting || createMutation.isPending}
          >
            {createMutation.isPending ? 'Creating…' : 'Create project'}
          </button>
        </div>
      </form>
    </div>
  );
}
